children.text:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: Arial, sans-serif; font-size: 16px; }

/* Section 1: Interactive form elements */
.form-section {
    padding: 10px;
    background: #f0f0f0;
}
#btn1 {
    display: inline-block;
    padding: 8px 24px;
    background: #4488cc;
    color: white;
    border: 1px solid #336699;
    font-size: 14px;
    cursor: pointer;
}
.radio-group, .checkbox-group {
    margin-top: 8px;
}
.radio-group label, .checkbox-group label {
    margin-right: 16px;
    font-size: 14px;
}

/* Section 2: Image and SVG */
.media-section {
    padding: 10px;
    background: #e8f4e8;
}
#img1 {
    width: 80px;
    height: 60px;
    background: #cc4444;
    display: inline-block;
}
#svg1 {
    width: 80px;
    height: 60px;
    display: inline-block;
    vertical-align: top;
}

/* Section 3: Table */
.table-section {
    padding: 10px;
    background: #e8e8f4;
}
table {
    border-collapse: collapse;
}
td, th {
    padding: 6px 12px;
    border: 1px solid #666;
    font-size: 14px;
}
th { background: #ddd; }

/* Section 5: Position relative */
.position-section {
    padding: 10px;
    background: #f4f4e8;
    position: relative;
    height: 100px;
}
#rel-box {
    position: relative;
    top: 10px;
    left: 20px;
    width: 120px;
    height: 30px;
    background: #88cc44;
    font-size: 14px;
    line-height: 30px;
    text-align: center;
}
#abs-box {
    position: absolute;
    top: 50px;
    right: 20px;
    width: 120px;
    height: 30px;
    background: #cc8844;
    font-size: 14px;
    line-height: 30px;
    text-align: center;
}
